// Transform script for 512x512 f32 matmul targeting GPU.
// Workgroup tiles: 64x64, reduction tile: 16, thread grid: 16x4.

module attributes { transform.with_named_sequence } {

  transform.named_sequence @gpu_matmul_strategy(
      %variant_op: !transform.any_op) {

    // Phase 1: Find the matmul
    %matmul = transform.structured.match ops{["linalg.matmul"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op

    // Phase 2: Tile to workgroups (GPU blocks)
    // 512/64 = 8 blocks per dimension -> 8x8 grid
    %tiled, %forall_grid =
      transform.structured.tile_using_forall %matmul
        tile_sizes [64, 64]
        ( mapping = [#gpu.block<y>, #gpu.block<x>] )
      : (!transform.any_op) -> (!transform.any_op, !transform.any_op)
    transform.iree.populate_workgroup_count_region_using_num_threads_slice
      %forall_grid : (!transform.any_op) -> ()

    // Phase 3: Tile reduction dimension (K=16)
    // Each thread accumulates 16 elements along K before writing back
    %tiled_k, %loop_k = transform.structured.tile_using_for %tiled [0, 0, 16]
      : (!transform.any_op) -> (!transform.any_op, !transform.op<"scf.for">)

    // Phase 4: Vectorize
    %func = transform.structured.match ops{["func.func"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
    transform.apply_patterns to %func {
      transform.apply_patterns.iree.fold_reshape_into_tensor_hal_interface
      transform.apply_patterns.linalg.fold_unit_extent_dims_via_slices
      transform.apply_patterns.vector.cast_away_vector_leading_one_dim
    } : !transform.any_op
    %func_v = transform.structured.vectorize_children_and_apply_patterns %func
      : (!transform.any_op) -> !transform.any_op

    // Phase 5: Canonicalize before bufferization
    transform.apply_patterns to %func_v {
      transform.apply_patterns.iree.fold_fill_into_pad
      transform.apply_patterns.linalg.tiling_canonicalization
      transform.apply_patterns.scf.for_loop_canonicalization
    } : !transform.any_op
    transform.apply_patterns to %func_v {
      transform.apply_patterns.tensor.reassociative_reshape_folding
      transform.apply_patterns.canonicalization
    } : !transform.any_op
    transform.apply_cse to %func_v : !transform.any_op

    // Phase 6: Bufferize (tensor -> memref)
    transform.iree.eliminate_empty_tensors %variant_op
      : (!transform.any_op) -> ()
    transform.apply_patterns to %func_v {
      transform.apply_patterns.linalg.erase_unnecessary_inputs
    } : !transform.any_op
    %buf = transform.iree.bufferize { target_gpu } %func_v
      : (!transform.any_op) -> (!transform.any_op)

    // Phase 7: Map to GPU threads
    // 16 threads in x * 4 threads in y = 64 threads per workgroup
    %func_final = transform.structured.match ops{["func.func"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
    transform.iree.forall_to_workgroup %func_final
      : (!transform.any_op) -> ()
    transform.iree.map_nested_forall_to_gpu_threads %func_final
      workgroup_dims = [16, 4, 1] : (!transform.any_op) -> ()

    transform.yield
  }

  // Matcher: select matmul ops
  transform.named_sequence @match_matmul(
      %op: !transform.any_op {transform.readonly}) -> (!transform.any_op) {
    transform.match.operation_name %op ["linalg.matmul"] : !transform.any_op
    transform.yield %op : !transform.any_op
  }

  // Annotator: wire the strategy to matched ops
  transform.named_sequence @set_matmul_strategy(
      %op: !transform.any_op {transform.readonly}) {
    %variant = transform.get_parent_op %op
      {op_name = "hal.executable.variant"}
      : (!transform.any_op) -> !transform.any_op
    %funcs = transform.structured.match ops{["func.func"]} in %variant
      : (!transform.any_op) -> !transform.any_op
    %info = transform.param.constant
      #iree_codegen.translation_info<
        pipeline = TransformDialectCodegen
        codegen_spec = @gpu_matmul_strategy> -> !transform.any_param
    transform.annotate %funcs "translation_info" = %info
      : !transform.any_op, !transform.any_param
    transform.yield
  }

  // Entry point
  transform.named_sequence @__kernel_config(
      %variant_op: !transform.any_op {transform.consumed})
    -> !transform.any_op
    attributes { iree_codegen.tuning_spec_entrypoint } {
    %res = transform.foreach_match in %variant_op
      @match_matmul -> @set_matmul_strategy
      : (!transform.any_op) -> !transform.any_op
    transform.yield %res : !transform.any_op
  }
}

// Transform dialect script for 512x512 f32 matmul on GPU.
// Tiles to 64x64 workgroups, reduction tile 16, vectorized,
// mapped to 16x4 thread grid (64 threads per workgroup).

module attributes { transform.with_named_sequence } {

transform.named_sequence @__kernel_config(%variant_op: !transform.any_op {transform.readonly}) {
  // Match the matmul operation.
  %matmul = transform.structured.match.operation_name %variant_op ["linalg.matmul"]
    : (!transform.any_op) -> !transform.any_op

  // Tile to workgroup-level: 64x64 on M and N dimensions.
  %tiled_op, %forall_op = transform.structured.tile_using_forall %matmul
    tile_sizes [64, 64]
    ( mapping = [#gpu.block<y>, #gpu.block<x>] )
    : (!transform.any_op) -> (!transform.any_op, !transform.any_op)

  // Tile the reduction (K) dimension by 16.
  %tiled_reduction, %loop = transform.structured.tile_using_for %tiled_op [0, 0, 16]
    : (!transform.any_op) -> (!transform.any_op, !transform.any_op)

  // Thread-level tiling: each thread computes a 4x16 tile.
  // 64/4 = 16 threads along M, 64/16 = 4 threads along N -> 16x4 grid.
  %tiled_thread, %forall_thread = transform.structured.tile_using_forall %tiled_reduction
    tile_sizes [4, 16]
    ( mapping = [#gpu.thread<y>, #gpu.thread<x>] )
    : (!transform.any_op) -> (!transform.any_op, !transform.any_op)

  // Vectorize the inner matmul tile.
  transform.structured.vectorize %tiled_thread vector_sizes [4, 16, 16]
    : !transform.any_op

  // Bufferize the entire module.
  %func = transform.structured.match.operation_name %variant_op ["func.func"]
    : (!transform.any_op) -> !transform.any_op
  transform.iree.eliminate_empty_tensors %func : (!transform.any_op) -> ()
  %bufferized = transform.iree.bufferize %variant_op : (!transform.any_op) -> !transform.any_op

  // Post-bufferization: get the updated func, then map forall to GPU ids.
  %func_2 = transform.structured.match.operation_name %bufferized ["func.func"]
    : (!transform.any_op) -> !transform.any_op
  transform.iree.forall_to_workgroup %func_2 : (!transform.any_op) -> ()
  transform.iree.map_nested_forall_to_gpu_threads %func_2
    workgroup_dims = [4, 16, 1]
    : (!transform.any_op) -> ()

  // Vector lowering.
  transform.apply_patterns to %func_2 {
    transform.apply_patterns.vector.lower_contraction lowering_strategy = "outerproduct"
    transform.apply_patterns.vector.transfer_permutation_patterns
    transform.apply_patterns.vector.lower_multi_reduction lowering_strategy = "innerparallel"
    transform.apply_patterns.vector.lower_shape_cast
    transform.apply_patterns.vector.lower_transpose lowering_strategy = "eltwise"
  } : !transform.any_op

  transform.yield
}

} // module

module @mmt_tuning_spec attributes { transform.with_named_sequence } {

  // Reusable base matcher: identifies f16*f16->f32 MMT pattern
  transform.named_sequence @match_mmt_f16_f16_f32(
      %root: !transform.any_op {transform.readonly}) -> !transform.any_op {
    transform.match.operation_name %root ["linalg.generic"] : !transform.any_op
    %ins, %outs = transform.iree.match.cast_compatible_dag_from_root %root {
      ^bb0(%lhs: tensor<?x?xf16>, %rhs: tensor<?x?xf16>, %out: tensor<?x?xf32>):
      %r = linalg.generic {
        indexing_maps = [affine_map<(d0, d1, d2) -> (d0, d2)>,
                         affine_map<(d0, d1, d2) -> (d1, d2)>,
                         affine_map<(d0, d1, d2) -> (d0, d1)>],
        iterator_types = ["parallel", "parallel", "reduction"]}
        ins(%lhs, %rhs : tensor<?x?xf16>, tensor<?x?xf16>)
        outs(%out : tensor<?x?xf32>) {
      ^bb0(%in: f16, %in_0: f16, %acc: f32):
        %0 = arith.extf %in : f16 to f32
        %1 = arith.extf %in_0 : f16 to f32
        %2 = arith.mulf %0, %1 : f32
        %3 = arith.addf %acc, %2 : f32
        linalg.yield %3 : f32
      } -> tensor<?x?xf32>
    } : (!transform.any_op) -> (!transform.any_value, !transform.any_value)
    transform.yield %root : !transform.any_op
  }

  // Shape-specific matcher: LHS 4096x4096, RHS 1024x4096
  transform.named_sequence @match_mmt_4096x1024x4096(
      %op: !transform.any_op {transform.readonly})
    -> (!transform.any_op, !transform.any_param) {
    %mmt = transform.include @match_mmt_f16_f16_f32 failures(propagate) (%op)
      : (!transform.any_op) -> !transform.any_op
    %lhs = transform.get_operand %op[0] : (!transform.any_op) -> !transform.any_value
    %rhs = transform.get_operand %op[1] : (!transform.any_op) -> !transform.any_value
    transform.iree.match.cast_compatible_type %lhs = tensor<4096x4096xf16>
      : !transform.any_value
    transform.iree.match.cast_compatible_type %rhs = tensor<1024x4096xf16>
      : !transform.any_value
    %config = transform.param.constant #iree_codegen.compilation_info<
      lowering_config = #iree_gpu.lowering_config<{
        promote_operands = [0, 1],
        mma_kind = #iree_gpu.mma_layout<MFMA_F32_16x16x16_F16>,
        subgroup_m_count = 2, subgroup_n_count = 2,
        reduction = [0, 0, 64],
        workgroup = [64, 128, 0]}>,
      translation_info = #iree_codegen.translation_info<
        pipeline = LLVMGPUVectorDistribute
        workgroup_size = [256, 1, 1] subgroup_size = 64,
        {gpu_pipeline_options = #iree_gpu.pipeline_options<
          prefetch_shared_memory = true>}>
    > -> !transform.any_param
    transform.yield %op, %config : !transform.any_op, !transform.any_param
  }

  // Generic annotator
  transform.named_sequence @apply_op_config(
      %op: !transform.any_op {transform.readonly},
      %config: !transform.any_param {transform.readonly}) {
    transform.annotate %op "compilation_info" = %config
      : !transform.any_op, !transform.any_param
    transform.annotate %op "__tuning_spec_applied__" : !transform.any_op
    transform.yield
  }

  // Entry point
  transform.named_sequence @__kernel_config(
      %variant_op: !transform.any_op {transform.consumed})
    -> !transform.any_op
    attributes { iree_codegen.tuning_spec_entrypoint } {
    %res = transform.foreach_match in %variant_op
      @match_mmt_4096x1024x4096 -> @apply_op_config
      : (!transform.any_op) -> !transform.any_op
    transform.yield %res : !transform.any_op
  }
}

// Transform library: matmul -> add -> relu fusion chain for GPU.
// Tiles relu by [32, 32], fuses add and matmul into the tiled loop,
// vectorizes, and bufferizes targeting GPU.

module attributes { transform.with_named_sequence } {

  transform.named_sequence @fusion_chain_gpu_strategy(
      %variant_op: !transform.any_op) {

    // Phase 1: Match all three ops in the chain
    %matmul = transform.structured.match ops{["linalg.matmul"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
    %fills = transform.structured.match ops{["linalg.fill"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
    %elemwise = transform.structured.match ops{["linalg.elemwise_binary"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op

    // Split elemwise handle into add and relu (in program order)
    %add, %relu = transform.split_handle %elemwise
      : (!transform.any_op) -> (!transform.any_op, !transform.any_op)

    // Phase 2: Tile the last op (relu) by [32, 32] to create the outer loop
    %tiled_relu, %forall = transform.structured.tile_using_forall %relu
      tile_sizes [32, 32]
      ( mapping = [#gpu.block<y>, #gpu.block<x>] )
      : (!transform.any_op) -> (!transform.any_op, !transform.any_op)
    transform.iree.populate_workgroup_count_region_using_num_threads_slice
      %forall : (!transform.any_op) -> ()

    // Phase 3: Fuse producers into the tiled loop (reverse dataflow order)
    // Fuse add into the loop (add feeds relu)
    %fused_add, %forall_1 =
      transform.structured.fuse_into_containing_op %add into %forall
      : (!transform.any_op, !transform.any_op)
      -> (!transform.any_op, !transform.any_op)

    // Fuse matmul into the loop (matmul feeds add)
    %fused_matmul, %forall_2 =
      transform.structured.fuse_into_containing_op %matmul into %forall_1
      : (!transform.any_op, !transform.any_op)
      -> (!transform.any_op, !transform.any_op)

    // Phase 4: Vectorize all linalg ops within the function
    %func = transform.structured.match ops{["func.func"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
    transform.apply_patterns to %func {
      transform.apply_patterns.iree.fold_reshape_into_tensor_hal_interface
      transform.apply_patterns.linalg.fold_unit_extent_dims_via_slices
      transform.apply_patterns.vector.cast_away_vector_leading_one_dim
    } : !transform.any_op
    %func_v = transform.structured.vectorize_children_and_apply_patterns %func
      : (!transform.any_op) -> !transform.any_op

    // Phase 5: Canonicalize before bufferization
    transform.apply_patterns to %func_v {
      transform.apply_patterns.iree.fold_fill_into_pad
      transform.apply_patterns.linalg.tiling_canonicalization
      transform.apply_patterns.scf.for_loop_canonicalization
    } : !transform.any_op
    transform.apply_patterns to %func_v {
      transform.apply_patterns.tensor.reassociative_reshape_folding
      transform.apply_patterns.canonicalization
    } : !transform.any_op
    transform.apply_cse to %func_v : !transform.any_op

    // Phase 6: Bufferize (tensor -> memref) targeting GPU
    transform.iree.eliminate_empty_tensors %variant_op
      : (!transform.any_op) -> ()
    transform.apply_patterns to %func_v {
      transform.apply_patterns.linalg.erase_unnecessary_inputs
    } : !transform.any_op
    %buf = transform.iree.bufferize { target_gpu } %func_v
      : (!transform.any_op) -> (!transform.any_op)

    // Phase 7: Map forall loops to GPU workgroups and threads
    %func_final = transform.structured.match ops{["func.func"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
    transform.iree.forall_to_workgroup %func_final
      : (!transform.any_op) -> ()
    transform.iree.map_nested_forall_to_gpu_threads %func_final
      workgroup_dims = [32, 1, 1] : (!transform.any_op) -> ()

    transform.yield
  }

  // Matcher: find a linalg.matmul as the root of the fusion chain
  transform.named_sequence @match_matmul(
      %op: !transform.any_op {transform.readonly}) -> (!transform.any_op) {
    transform.match.operation_name %op ["linalg.matmul"] : !transform.any_op
    transform.yield %op : !transform.any_op
  }

  // Annotator: wire the fusion chain strategy via TransformDialectCodegen
  transform.named_sequence @set_fusion_strategy(
      %op: !transform.any_op {transform.readonly}) {
    %variant = transform.get_parent_op %op
      {op_name = "hal.executable.variant"}
      : (!transform.any_op) -> !transform.any_op
    %funcs = transform.structured.match ops{["func.func"]} in %variant
      : (!transform.any_op) -> !transform.any_op
    %info = transform.param.constant
      #iree_codegen.translation_info<
        pipeline = TransformDialectCodegen
        codegen_spec = @fusion_chain_gpu_strategy> -> !transform.any_param
    transform.annotate %funcs "translation_info" = %info
      : !transform.any_op, !transform.any_param
    transform.yield
  }

  // Entry point
  transform.named_sequence @__kernel_config(
      %variant_op: !transform.any_op {transform.consumed})
    -> !transform.any_op
    attributes { iree_codegen.tuning_spec_entrypoint } {
    %res = transform.foreach_match in %variant_op
      @match_matmul -> @set_fusion_strategy
      : (!transform.any_op) -> !transform.any_op
    transform.yield %res : !transform.any_op
  }
}

// Transform library: matmul -> add -> relu fusion chain
// Tiles relu by [32,32], fuses add and matmul into the tiled loop,
// then vectorizes and bufferizes for GPU.

module attributes {transform.with_named_sequence} {

transform.named_sequence @__kernel_config(%variant_op: !transform.any_op {transform.consumed}) {
  // ---------------------------------------------------------------
  // 1. Match the three ops in the chain: matmul, add, relu
  // ---------------------------------------------------------------
  %matmul = transform.structured.match ops{["linalg.matmul"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
  %add = transform.structured.match ops{["linalg.generic"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
  %relu = transform.structured.match ops{["linalg.generic"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op

  // ---------------------------------------------------------------
  // 2. Tile the relu (consumer) by [32, 32]
  // ---------------------------------------------------------------
  %tiled_relu, %forall =
      transform.structured.tile_using_forall %relu
          tile_sizes [32, 32]
          ( mapping = [#gpu.block<y>, #gpu.block<x>] )
      : (!transform.any_op) -> (!transform.any_op, !transform.any_op)

  // ---------------------------------------------------------------
  // 3. Fuse add into the tiled loop
  // ---------------------------------------------------------------
  %fused_add, %new_forall_0 =
      transform.structured.fuse_into_containing_op %add into %forall
      : (!transform.any_op, !transform.any_op)
          -> (!transform.any_op, !transform.any_op)

  // ---------------------------------------------------------------
  // 4. Fuse matmul into the tiled loop
  // ---------------------------------------------------------------
  %fused_matmul, %new_forall_1 =
      transform.structured.fuse_into_containing_op %matmul into %new_forall_0
      : (!transform.any_op, !transform.any_op)
          -> (!transform.any_op, !transform.any_op)

  // ---------------------------------------------------------------
  // 5. Tile the fused matmul reduction dim for register reuse
  // ---------------------------------------------------------------
  %tiled_matmul, %loop =
      transform.structured.tile_using_for %fused_matmul [0, 0, 32]
      : (!transform.any_op) -> (!transform.any_op, !transform.any_op)

  // ---------------------------------------------------------------
  // 6. Vectorize all ops inside the fusion region
  // ---------------------------------------------------------------
  %func = transform.structured.match ops{["func.func"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op

  transform.structured.vectorize %tiled_matmul
      : !transform.any_op
  transform.structured.vectorize %fused_add
      : !transform.any_op
  transform.structured.vectorize %tiled_relu
      : !transform.any_op

  // ---------------------------------------------------------------
  // 7. Canonicalize / CSE cleanup after vectorization
  // ---------------------------------------------------------------
  %func_v = transform.structured.match ops{["func.func"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
  transform.apply_patterns to %func_v {
    transform.apply_patterns.canonicalization
  } : !transform.any_op
  transform.apply_cse to %func_v : !transform.any_op

  // ---------------------------------------------------------------
  // 8. Bufferize (one-shot) for GPU memory semantics
  // ---------------------------------------------------------------
  %bufferized = transform.bufferization.one_shot_bufferize
      layout{IdentityLayoutMap}
      %variant_op {
        bufferize_function_boundaries = true,
        allow_return_allocs_from_loops = true
      } : (!transform.any_op) -> !transform.any_op

  // ---------------------------------------------------------------
  // 9. Map the forall to GPU thread/block grid
  // ---------------------------------------------------------------
  %mapped_func = transform.structured.match ops{["func.func"]} in %bufferized
      : (!transform.any_op) -> !transform.any_op
  transform.iree.map_nested_forall_to_gpu_threads %mapped_func
      workgroup_dims = [32, 32, 1]
      : (!transform.any_op) -> !transform.any_op

  // ---------------------------------------------------------------
  // 10. Final cleanup
  // ---------------------------------------------------------------
  %final_func = transform.structured.match ops{["func.func"]} in %bufferized
      : (!transform.any_op) -> !transform.any_op
  transform.apply_patterns to %final_func {
    transform.apply_patterns.canonicalization
  } : !transform.any_op
  transform.apply_cse to %final_func : !transform.any_op

  transform.yield
}

} // module

