    def get_root_dir(self):
        return self._root_dir_abs

    def get_entry_src_dir(self):
        return self._root_dir_abs / "src"

    def get_thirdparty_dir(self):
        return self._root_dir_abs / "third-party"

    def get_relpath_to_workdir(self, p: Path):
        return p.relative_to(
            self._working_dir_abs.relative_to(self._root_dir_abs))

    # model
    def get_model_path_abs(self):
        return self._model_path_abs

