from pydantic import BaseModel, field_validator, ConfigDict, ValidationError
import toml
from typing import Optional

from auto_iree.device import Device, \
    GDBDevice, \
    QEMUBarementalDevice, \
    QEMUSystemDevice, \
    CustomDevice0


class LLVMConfig(BaseModel):
    cpu: str = "generic-rv64"
    triple: str
    attr: str
    vlen: int

    @field_validator('cpu')
    @classmethod
    def check_cpu(cls, cpu: str) -> str:
        if cpu == "generic-rv64":
            return cpu
        raise ValueError("Current only support cpu: generic-rv64")

    @field_validator('vlen')
    @classmethod
    def check_vlen(cls, v: int) -> int:
        if v == 128 or v == 256 or v == 512 or v == 1024:
            return v
        raise ValueError(f"Invalid vlen: {v}")

    def share_to_qemu(self, qd: QEMUBarementalDevice | None):
        if isinstance(qd, QEMUBarementalDevice):
            qd.set_cpu(self.cpu, self.vlen)


class BuildConfig(BaseModel):
    riscv_toolchain: Path
    compile_time_adjust_factor: float
    run_time_adjust_factor: float
    llvm: LLVMConfig

    # model_config = ConfigDict(protected_namespaces=())

    @field_validator('riscv_toolchain')
    @classmethod
    def check_dir_exists(cls, v: Path) -> Path:
        if not v.is_dir():
            raise ValueError(f"Dir does not exist: {str(v)}")
        return v


class TargetConfig(BaseModel):
    device: str
    gdb: Optional[GDBDevice] = None
    qemu_bare: Optional[QEMUBarementalDevice] = None
    qemu_system: Optional[QEMUSystemDevice] = None
    custom0: Optional[CustomDevice0] = None

    def isValid(self):
        if self.device == "gdb" and self.gdb is not None:
            return True
        if self.device == "qemu_bare" and self.qemu_bare is not None:
            return True
        if self.device == "qemu_system" and self.qemu_system is not None:
            return True
        if self.device == "custom0" and self.custom0 is not None:
            return True        

        return False

    def getDevice(self) -> Device:
        if self.isValid():
            if self.device == "gdb":
                assert isinstance(self.gdb, GDBDevice)
                return self.gdb
            if self.device == "qemu_bare":
                assert isinstance(self.qemu_bare, QEMUBarementalDevice)
                return self.qemu_bare
            if self.device == "qemu_system":
                assert isinstance(self.qemu_system, QEMUSystemDevice)
                return self.qemu_system
            if self.device == "custom0":
                assert isinstance(self.custom0, CustomDevice0)
                return self.custom0

        raise ValueError("Cannot get a valid device")


class Config(BaseModel):
    build: BuildConfig
    target: TargetConfig
    dryrun: bool

    model_config = ConfigDict(extra='forbid')


def load_config(path: str) -> Config:
    try:
        with open(path, 'r') as f:
            toml_data = toml.load(f)

        config = Config.model_validate(toml_data)
        config.build.llvm.share_to_qemu(config.target.qemu_bare)

        return config
    except toml.TomlDecodeError as e:
        print(f"Error decoding TOML file: {e}")
        raise
    except FileNotFoundError:
        print(f"Configuration file not found: {path}")
        raise
    except ValidationError as e:
        print("Configuration validation error:")
        for error in e.errors():
            print(f"- {' -> '.join(map(str, error['loc']))}: {error['msg']}")
        raise


def get_device_from_config(path: str) -> Device:
    config = load_config(path)
    return config.target.getDevice()

